#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld",&N);
        long long ans = (N%2==0) ? (N/2) : (-(N+1)/2);
        printf("%lld\n", ans);
    }
    return 0;
}

